import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import timeGridPlugin from '@fullcalendar/timegrid'



class RoomAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            screen: 0, roomResults: [], reservationResults: [], addRoom: false, addroomName: "", addroomEmployeeRoom: false
        };
    }

    updateRoomName = (event) => {
        this.setState({addRoomName: event.target.value})
    }

    handleEmployeeRoomChange = (event) => {
        this.setState({addroomEmployeeRoom: event.target.checked})
    }

    handleDeleteRoom = (item) => {
        if (window.confirm('Are you sure you wish to delete ' + item.room_name)) {
            this.setState({screen: 0})

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + `deleteRoom?id=` + item.id, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({roomResults: response})
                this.setState({screen: 1})
                this.setState({addRoom: false})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });

        }
    }

    handleEditRoom = (editItem) => {

    }  

    handleAddRoom = () => {
        this.setState({addRoom: true})
    }


    componentDidMount() {

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getavailableroom`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {
            //console.log(response);
            this.setState({roomResults: response})
            this.setState({addRoom: false})
            //this.setState({screen: 1})
            //_forEach(response, d => console.log(d.name))
            //console.log(this.state.results)

            fetch(properties.backend + `getreservation?all=1`, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({reservationResults: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });



          })
          .catch(err => {
            console.log(err);
          });





    }


    render() {


        var header = "Loading ..."
        var content = []
        var rightContent = []
        var leftContent = []


        if (this.state.screen === 1) {
            var tabContent = []
            //leftContent.push(<div>left</div>)
            //rightContent.push(<div>right</div>)

            var roomResults = this.state.roomResults

            //for (var index in roomResults) {
            roomResults.map(roomResult => {
                //var roomResult = roomResults[index]
                var leftContent2 = []
                var rightContent2 = []
                leftContent2.push(<div style={{marginBottom: "5px"}}>Room: {roomResult.room_name}</div>)
                if (roomResult.owner.length > 0) {
                    leftContent2.push(<div style={{marginBottom: "5px"}}>Employee: {roomResult.owner}</div>)
                }
                rightContent2.push(<div><button onClick={() => this.handleEditRoom(roomResult)}  id={"editRoom" + roomResult.id} style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Edit</button>&nbsp;&nbsp;<button onClick={() => this.handleDeleteRoom(roomResult)} id={"deleteRoom" + roomResult.id}  style={{height: "25px", width: "60px", fontSize: "14px", backgroundColor: "lightgrey" }}>Delete</button></div>)
                leftContent.push(<div style={{display: "flex"}}><div style={{marginRight: "20px", width: "450px"}}>{leftContent2}</div><div style={{flex: "100%"}}>{rightContent2}</div></div>)
                leftContent.push(<div style={{marginBottom: "5px"}}><hr></hr></div>)
            })


            if (this.state.addRoom) {
                var tempContent = []

                tempContent.push(<div>Add Room<hr></hr></div>)
                tempContent.push(<div style={{marginBottom:"5px"}}>Room Name: <input type="text" onChange={event => this.updateRoomName(event)}></input></div>)
                tempContent.push(<div style={{marginBottom:"5px"}}>Employee Room: <input type="checkbox" onChange={event => this.handleEmployeeRoomChange(event)}></input></div>)



                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelBooking()}  id="cancelBooking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleBooking()}  id="booking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


                rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
            }


            tabContent.push(<Tabs>
                <TabList>
                    <Tab>Manage Rooms</Tab>
                    <Tab>Manage Reservation</Tab>
                </TabList>
                <TabPanel>
                    <h2><button onClick={() => this.handleAddRoom()}  id="addRoom" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}> + Add Room</button></h2>
                    <div></div>
                    <div style={{display: "flex"}}><div style={{marginRight: "50px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>
                </TabPanel>
                <TabPanel>
                    <h2>Manage Reservation</h2>
                </TabPanel>
            </Tabs>)

            content.push(tabContent)
            header = ""
        }

        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }





}


export default RoomAdmin
